        long currentTime = System.currentTimeMillis();
        curentSize = (int)Math.max(0,curentSize - (currentTime - now) *rate);
        if(curentSize < size){
            now  = currentTime;
            curentSize++;
            return true;
        }else{
            return false;
        }
    }

    //令牌桶算法
