        long currentTime = System.currentTimeMillis();
        curentSize = (int)Math.min(size,curentSize + (currentTime - now) *rate);
        if(curentSize > 0){
            now  = currentTime;
            curentSize--;
            return true;
        }else{
            return false;
        }
